// package-lock-generator.js

const fs = require('fs');
const path = require('path');

function generatePackageLock(projectPath) {
  try {
    const packageJsonPath = path.join(projectPath, 'package.json');
    const lockFilePath = path.join(projectPath, 'package-lock.json');

    // Read the package.json file
    const packageJsonContent = fs.readFileSync(packageJsonPath, 'utf8');
    const packageJson = JSON.parse(packageJsonContent);

    // Generate the package-lock.json content (simplified example)
    const packageLockContent = {
      name: packageJson.name,
      version: packageJson.version,
      dependencies: {},
    };

    // Populate dependencies (simplified example)
    for (const [name, version] of Object.entries(packageJson.dependencies)) {
      packageLockContent.dependencies[name] = { version };
    }

    // Write the package-lock.json file
    fs.writeFileSync(lockFilePath, JSON.stringify(packageLockContent, null, 2));
    console.log('package-lock.json generated successfully.');
  } catch (error) {
    console.error('Error generating package-lock.json:', error);
  }
}

